// Topic formats:
//   building/{bId}/zone/{zId}/{type}/{devId}  → type in parts[4]
//   building/{bId}/network/{subtype}           → type = 'network'

const parts = msg.topic.split('/');

// Defensive JSON parse if payload arrived as string
if (typeof msg.payload === 'string') {
    try {
        msg.payload = JSON.parse(msg.payload);
    } catch (e) {
        node.error('Invalid JSON payload on topic: ' + msg.topic, msg);
        return null;
    }
}

if (parts.length >= 4 && parts[2] === 'network') {
    msg.sensorType    = 'network';
    msg.networkSubtype = parts[3];   // 'flow' or 'alert'
    msg.buildingId    = parts[1];
    msg.zoneId        = null;
    msg.deviceId      = parts[3];
} else if (parts.length >= 6) {
    msg.sensorType = parts[4];       // badge | door | motion | camera
    msg.buildingId = parts[1];
    msg.zoneId     = parts[3];
    msg.deviceId   = parts[5];
} else {
    node.warn('Unrecognised topic structure: ' + msg.topic);
    return null;
}

return msg;

// BADGE_ACCESS — NODERED_CONTRACT.md §5.1
// Required: badge_id, access_result
// access_result ∈ {GRANTED, DENIED, TIMEOUT}
const p = msg.payload;
const VALID_RESULTS = ['GRANTED', 'DENIED', 'TIMEOUT'];

if (!p || typeof p !== 'object') {
    msg.validationError = 'payload is not an object';
    return [null, msg];
}
const missing = ['badge_id', 'access_result'].filter(f => p[f] == null);
if (missing.length) {
    msg.validationError = 'Missing required fields: ' + missing.join(', ');
    return [null, msg];
}
if (!VALID_RESULTS.includes(p.access_result)) {
    msg.validationError = 'Invalid access_result: ' + p.access_result +
        ' — expected one of ' + VALID_RESULTS.join('|');
    return [null, msg];
}

return [msg, null];

// DOOR_OPENED / DOOR_CLOSED / DOOR_FORCED — NODERED_CONTRACT.md §5.2
// Required: door_id
// Optional: duration_open_seconds (number if present)
const p = msg.payload;

if (!p || typeof p !== 'object') {
    msg.validationError = 'payload is not an object';
    return [null, msg];
}
if (!p.door_id) {
    msg.validationError = 'Missing required field: door_id';
    return [null, msg];
}
if (p.duration_open_seconds !== undefined && p.duration_open_seconds !== null) {
    if (typeof p.duration_open_seconds !== 'number') {
        msg.validationError = 'duration_open_seconds must be a number, got: ' +
            typeof p.duration_open_seconds;
        return [null, msg];
    }
}

return [msg, null];

// MOTION_DETECTED — NODERED_CONTRACT.md §5.3
// Required: detector_device_id
// Optional: entity_count (integer >= 1 if present)
const p = msg.payload;

if (!p || typeof p !== 'object') {
    msg.validationError = 'payload is not an object';
    return [null, msg];
}
if (!p.detector_device_id) {
    msg.validationError = 'Missing required field: detector_device_id';
    return [null, msg];
}
if (p.entity_count !== undefined && p.entity_count !== null) {
    if (!Number.isInteger(p.entity_count) || p.entity_count < 1) {
        msg.validationError = 'entity_count must be an integer >= 1, got: ' + p.entity_count;
        return [null, msg];
    }
}

return [msg, null];

// CAMERA_EVENT — NODERED_CONTRACT.md §5.6
// Required: camera_device_id, event_subtype
// Optional: snapshot_url
const p = msg.payload;

if (!p || typeof p !== 'object') {
    msg.validationError = 'payload is not an object';
    return [null, msg];
}
const missing = ['camera_device_id', 'event_subtype'].filter(f => !p[f]);
if (missing.length) {
    msg.validationError = 'Missing required fields: ' + missing.join(', ');
    return [null, msg];
}
// snapshot_url is optional (string or null)
if (p.snapshot_url !== undefined && p.snapshot_url !== null &&
    typeof p.snapshot_url !== 'string') {
    msg.validationError = 'snapshot_url must be a string or null';
    return [null, msg];
}

return [msg, null];

// NETWORK_FLOW (§5.4) or NETWORK_ANOMALY (§5.5)
// Dispatched via msg.networkSubtype set by Extract Sensor Type:
//   topic building/B1/network/flow  → subtype = 'flow'
//   topic building/B1/network/alert → subtype = 'alert'
const p = msg.payload;
const subtype = msg.networkSubtype || '';

if (!p || typeof p !== 'object') {
    msg.validationError = 'payload is not an object';
    return [null, msg];
}

if (subtype === 'flow') {
    // NETWORK_FLOW required fields
    const PROTOCOLS = ['TCP', 'UDP', 'ICMP'];
    const required  = ['src_ip', 'dst_ip', 'protocol', 'bytes_sent', 'bytes_received'];
    const missing   = required.filter(f => p[f] == null);
    if (missing.length) {
        msg.validationError = 'Missing required fields: ' + missing.join(', ');
        return [null, msg];
    }
    if (!PROTOCOLS.includes(p.protocol)) {
        msg.validationError = 'Invalid protocol: ' + p.protocol +
            ' — expected one of ' + PROTOCOLS.join('|');
        return [null, msg];
    }
    if (!Number.isInteger(p.bytes_sent) || p.bytes_sent < 0) {
        msg.validationError = 'bytes_sent must be integer >= 0';
        return [null, msg];
    }
    if (!Number.isInteger(p.bytes_received) || p.bytes_received < 0) {
        msg.validationError = 'bytes_received must be integer >= 0';
        return [null, msg];
    }

} else if (subtype === 'alert') {
    // NETWORK_ANOMALY required fields
    const LABELS = ['PORT_SCAN','EXFILTRATION','C2_BEACON','LATERAL_MOVEMENT','DOS','UNKNOWN'];
    if (!p.label) {
        msg.validationError = 'Missing required field: label';
        return [null, msg];
    }
    if (!LABELS.includes(p.label)) {
        msg.validationError = 'Invalid label: ' + p.label +
            ' — expected one of ' + LABELS.join('|');
        return [null, msg];
    }
    if (!p.evidence) {
        msg.validationError = 'Missing required field: evidence';
        return [null, msg];
    }

} else {
    msg.validationError = 'Unknown network subtype: "' + subtype +
        '" — expected "flow" or "alert"';
    return [null, msg];
}

return [msg, null];

// Flow 1 sets on msg: sensorType, networkSubtype, buildingId, zoneId, deviceId
// msg.payload = validated raw sensor payload
// crypto.randomUUID not available in Node-RED function sandbox
   // Use simple UUID v4 generator instead
   function uuidv4() {
       return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c) {
           var r = Math.random() * 16 | 0;
           var v = c === 'x' ? r : (r & 0x3 | 0x8);
           return v.toString(16);
       });
   }
const p          = msg.payload;
const sensorType = msg.sensorType     || '';
const netSubtype = msg.networkSubtype || '';
const buildingId = msg.buildingId     || 'B1';
const zoneId     = msg.zoneId         || 'GLOBAL'; // network events carry no zone in topic
const deviceId   = msg.deviceId       || 'UNKNOWN';

// ── 1. event_type ────────────────────────────────────────────────────
let eventType;
switch (sensorType) {
    case 'badge':   eventType = 'BADGE_ACCESS';   break;
    case 'motion':  eventType = 'MOTION_DETECTED'; break;
    case 'camera':  eventType = 'CAMERA_EVENT';    break;
    case 'network': eventType = netSubtype === 'alert' ? 'NETWORK_ANOMALY' : 'NETWORK_FLOW'; break;
    case 'door': {
        const s = (p.state || '').toUpperCase();
        eventType = s === 'FORCED'                    ? 'DOOR_FORCED'
                  : (s === 'CLOSE' || s === 'CLOSED') ? 'DOOR_CLOSED'
                  : 'DOOR_OPENED';
        break;
    }
    default:
        node.error('Unknown sensorType: ' + sensorType, msg);
        return null;
}

// ── 2. source_layer ──────────────────────────────────────────────────
const sourceLayer = sensorType === 'network' ? 'CYBER' : 'PHYSICAL';

// ── 3. severity_raw ──────────────────────────────────────────────────
let severityRaw = 'INFO';
if (eventType === 'BADGE_ACCESS' &&
    (p.access_result === 'DENIED' || p.access_result === 'TIMEOUT')) {
    severityRaw = 'WARNING';
} else if (eventType === 'DOOR_FORCED' || eventType === 'NETWORK_ANOMALY') {
    severityRaw = 'ALERT';
}

// ── 4. payload (kind MUST equal event_type — Pydantic discriminated union) ──
let normalizedPayload;
if (eventType === 'BADGE_ACCESS') {
    normalizedPayload = {
        kind:             eventType,
        badge_id:         p.badge_id,
        reader_device_id: p.reader_device_id || deviceId,
        access_result:    p.access_result
    };
} else if (eventType === 'DOOR_OPENED' ||
           eventType === 'DOOR_CLOSED' ||
           eventType === 'DOOR_FORCED') {
    normalizedPayload = { kind: eventType, door_id: p.door_id };
    if (p.duration_open_seconds != null) {
        normalizedPayload.duration_open_seconds = p.duration_open_seconds;
    }
} else if (eventType === 'MOTION_DETECTED') {
    normalizedPayload = {
        kind:               eventType,
        detector_device_id: p.detector_device_id
    };
    if (p.entity_count != null) {
        normalizedPayload.entity_count = p.entity_count;
    }
} else if (eventType === 'CAMERA_EVENT') {
    normalizedPayload = {
        kind:             eventType,
        camera_device_id: p.camera_device_id,
        event_subtype:    p.event_subtype,
        snapshot_url:     p.snapshot_url != null ? p.snapshot_url : null
    };
} else if (eventType === 'NETWORK_FLOW') {
    normalizedPayload = {
        kind:               eventType,
        src_ip:             p.src_ip,
        dst_ip:             p.dst_ip,
        dst_port:           p.dst_port           != null ? p.dst_port           : null,
        protocol:           p.protocol,
        bytes_sent:         p.bytes_sent,
        bytes_received:     p.bytes_received,
        duration_seconds:   p.duration_seconds   != null ? p.duration_seconds   : null,
        distinct_dst_ports: p.distinct_dst_ports  != null ? p.distinct_dst_ports : null
    };
} else if (eventType === 'NETWORK_ANOMALY') {
    normalizedPayload = {
        kind:     eventType,
        label:    p.label,
        evidence: p.evidence
    };
}

// ── 5. Assemble the 13-field UnifiedEvent ────────────────────────────
// ai_score and ai_classification MUST NOT be present (Pydantic extra='forbid')
// The AI engine fills them downstream after consuming events.raw.
msg.payload = {
    event_id:            uuidv4(),
    event_type:          eventType,
    source_layer:        sourceLayer,
    timestamp:           p.timestamp || new Date().toISOString(),
    building_id:         buildingId,
    zone_id:             zoneId,
    device_id:           deviceId,
    user_id:             p.user_id != null ? p.user_id : null,
    severity_raw:        severityRaw,
    payload:             normalizedPayload,
    correlated_events:   [],
    schema_version:      '1.0.0',
    ingestion_timestamp: new Date().toISOString()
};

return msg;

// Final gate before events.raw — mirrors Pydantic constraints (extra='forbid')
const e = msg.payload;

const REQUIRED = [
    'event_id', 'event_type', 'source_layer', 'timestamp',
    'building_id', 'zone_id', 'device_id', 'user_id',
    'severity_raw', 'payload', 'correlated_events',
    'schema_version', 'ingestion_timestamp'
];
const PROHIBITED = ['ai_score', 'ai_classification'];

// All 13 required fields must be defined
// user_id: null is valid (contract allows null) — only undefined is rejected
const missing = REQUIRED.filter(f => e[f] === undefined);
if (missing.length) {
    msg.validationError = 'Missing required fields: ' + missing.join(', ');
    return [null, msg];
}

// Prohibited fields must be absent — AI engine fills these downstream
const forbidden = PROHIBITED.filter(f => e[f] !== undefined);
if (forbidden.length) {
    msg.validationError = 'Prohibited fields present (AI engine fills them): ' + forbidden.join(', ');
    return [null, msg];
}

// payload.kind must equal event_type (Pydantic discriminated union)
if (!e.payload || e.payload.kind !== e.event_type) {
    msg.validationError =
        'payload.kind (' + (e.payload && e.payload.kind) + ')' +
        ' != event_type (' + e.event_type + ')';
    return [null, msg];
}

// correlated_events must be an array (may be empty)
if (!Array.isArray(e.correlated_events)) {
    msg.validationError = 'correlated_events must be an array, got: ' + typeof e.correlated_events;
    return [null, msg];
}

// schema_version must be pinned to contract version
if (e.schema_version !== '1.0.0') {
    msg.validationError = 'schema_version must be "1.0.0", got: ' + e.schema_version;
    return [null, msg];
}

return [msg, null];

// Record the current timestamp for this device in flow context.
// flow.lastSeen = { [deviceId]: epochMs, ... }
// Shared with 'Check device health' on the timer path.
if (!msg.deviceId) {
    return null; // skip messages with no deviceId (safety guard)
}

const lastSeen = flow.get('lastSeen') || {};
lastSeen[msg.deviceId] = Date.now();
flow.set('lastSeen', lastSeen);

// No output — this node is a pure side-effect sink
return null;

// Reads flow.lastSeen and flags devices silent for > OFFLINE_THRESHOLD_MS.
// Returns one msg per offline device on output 1, or null if all healthy.
const OFFLINE_THRESHOLD_MS = 120000; // 2 minutes

const lastSeen = flow.get('lastSeen');
if (!lastSeen || Object.keys(lastSeen).length === 0) {
    return null; // no devices seen yet — nothing to check
}

const now = Date.now();
const offlineMsgs = [];

for (const deviceId of Object.keys(lastSeen)) {
    const lastTs = lastSeen[deviceId];
    if (now - lastTs > OFFLINE_THRESHOLD_MS) {
        // Build a DEVICE_STATUS message — NODERED_CONTRACT.md §5.7
        offlineMsgs.push({
            topic:      'building/B1/zone/GLOBAL/device/' + deviceId,
            sensorType: 'device_status',
            deviceId:   deviceId,
            buildingId: 'B1',
            zoneId:     'GLOBAL',
            payload: {
                kind:           'DEVICE_STATUS',
                status:         'OFFLINE',
                last_heartbeat: new Date(lastTs).toISOString()
            }
        });
    }
}

if (offlineMsgs.length === 0) {
    return null; // all devices healthy
}

// [[msg1, msg2, ...]] — Node-RED sends each element as a separate message on output 1
return [offlineMsgs];
